(function (D) {
  'use strict';
  var SA = 'Software Architect', SO = 'Solution Architect', AA = 'Application Architect', EA = 'Enterprise Architect',
      CA = 'Cloud Architect', IA = 'Integration Architect', DA = 'Data Architect', SEC = 'Security Architect',
      PA = 'Platform Architect', MA = 'Microservices Architect', KA = 'Kafka Architect', JA = 'Java Application Architect';

  var Q = [
  /* ---- Introduction / Experience ---- */
  ['gi1',[SA,SO,AA],'Introduction','Beginner','Tell me about yourself and your path toward architecture.',
   'Communication, self-awareness, relevance filtering.','60–90 seconds: current role → 2–3 relevant achievements → why architecture → why this role.',
   [['Concise, structured narrative','structure','concise','minute'],['Concrete architecture-relevant achievements','designed','led','migration','platform'],['Motivation linked to the role','why','motivat','goal']],
   'A tight arc: years of engineering, the moment responsibility shifted from code to decisions (a migration or platform design), what you own today, and why this role is the logical next step.',
   'A chronological CV recital with no selection or arc.',
   ['What decision are you proudest of?','What would your last team say about you?'],['f1','m6']],
  ['gi2',[SA,SO],'Introduction','Beginner','What does a software architect actually do day to day, in your view?',
   'Realistic understanding of the role beyond diagrams.','Decision loop → stakeholders → artifacts → verification.',
   [['Decisions and trade-offs as the core','decision','trade-off','options'],['Stakeholder communication','stakeholder','business','communicate'],['Verification: reviews, fitness functions','review','fitness','verify']],
   'Understanding drivers, exploring options, deciding with recorded trade-offs, communicating per audience, and verifying the built system matches — diagrams and documents are outputs of that loop, not the job.',
   'Talking only about drawing diagrams or approving PRs.',
   ['How much should an architect code?','How do you stay grounded in delivery?'],['f1','f10']],
  ['gi3',[SA,SO,AA],'Experience','Intermediate','Describe an architecture decision you made that you later regretted. What did you learn?',
   'Honesty, learning loop, decision hygiene.','Situation → decision and rationale → what went wrong → what changed in your process.',
   [['Honest ownership of the mistake','wrong','mistake','regret','my'],['Root cause in the decision process','assumption','validate','context'],['A concrete process change','adr','review date','since then','now i']],
   'A real example (e.g. choosing microservices too early for a small team), the unvalidated assumption behind it, the cost, and the durable fix — writing assumptions into ADRs with review dates.',
   'A humble-brag ("I cared too much about quality") or blaming others.',
   ['How do you catch such mistakes earlier now?'],['a12','m6']],
  ['gi4',[SA,SO,EA],'Experience','Advanced','Walk me through the most complex system you have designed. What made it hard?',
   'Depth of real experience; complexity discrimination.','Context → the genuinely hard part (scale? consistency? organisation?) → key decisions → outcome.',
   [['Identifies the true source of difficulty','hard','complex','because'],['Concrete NFR numbers','rps','latency','availability','volume'],['Trade-offs and rejected options','trade-off','rejected','instead'],['Outcome with evidence','production','result','measured']],
   'Names the dominant complexity honestly (often organisational or consistency-related, not raw scale), gives real numbers, and shows two decisions with the option that lost and why.',
   'Complexity theatre — many technologies listed, no explanation of why any were needed.',
   ['What would you simplify today?','Which decision came closest to being wrong?'],['f4','a3']],

  /* ---- Fundamentals ---- */
  ['gi5',[SA,AA],'Fundamentals','Beginner','What is the difference between architecture and design?',
   'Conceptual clarity on significance and reversibility.','Definition → the cost-of-change test → examples → the fuzzy boundary.',
   [['Significant, hard-to-reverse decisions','significant','expensive','reverse','change'],['Design as local, reversible structure','local','internal','class'],['Context-dependence of the boundary','context','depends']],
   'Architecture is the set of decisions that are expensive to change and shape system-wide qualities; design is local structure reversible with local effort. The test: what does fixing it cost in a year? The boundary shifts with context.',
   'Architecture = high level, design = low level, with no test attached.',
   ['Give a decision that is design in one company and architecture in another.'],['f1']],
  ['gi6',[SA,SO],'Fundamentals','Beginner','Why do non-functional requirements drive architecture more than features?',
   'Understanding of quality attributes as shapers.','Claim → same-features-different-NFRs example → measurable scenarios.',
   [['Features = boxes, qualities = arrangement','feature','quality','shape','arrange'],['Concrete contrast example','example','50','20,000','99.9'],['Measurability requirement','measur','percentile','scenario']],
   'Two systems with identical features but 50 vs 20,000 RPS and 99.5 vs 99.99% availability need different architectures: partitioning, async pipelines, multi-zone. Features fill boxes; NFRs arrange them — and only measurable NFRs can be designed for.',
   'Reciting the NFR list without explaining the shaping effect.',
   ['Make "the system must be fast" measurable.'],['f4']],
  ['gi7',[SA,AA,MA],'Fundamentals','Intermediate','Explain coupling and cohesion, and how they show up at system scale.',
   'Whether principles scale beyond classes.','Definitions → coupling flavours → system-scale examples.',
   [['Correct definitions','cohesion','coupling','depend'],['Coupling flavours: schema, temporal, contract','schema','temporal','contract','shared database'],['System-scale example','service','database','synchronous']],
   'Cohesion: responsibilities that belong together stay together; coupling: dependence on internals or timing. Shared-database coupling is worst (schema hostage), temporal coupling means you fail when they fail (every sync call), contract coupling is normal when versioned.',
   'Textbook definitions with no flavours and no examples.',
   ['Which coupling does an event backbone remove, and which does it keep?'],['f5','a6']],
  ['gi8',[SA,SO],'Fundamentals','Intermediate','How do you document architecture decisions, and why that way?',
   'Professional decision hygiene.','ADR anatomy → what qualifies → immutability → where they live.',
   [['ADR structure: context, options, decision, consequences','adr','context','consequence','options'],['Significance filter','significant','reversible','trivial'],['Supersede, never edit','supersede','immutable'],['Negative consequences included','negative','downside','accept']],
   'ADRs with context, genuine options, the decision, and consequences including the negative ones; written for decisions that are hard to reverse or cross teams; immutable once accepted — superseded, not edited — so future teams see why, not just what.',
   'Confluence pages nobody can find, or an ADR with no downsides.',
   ['What was your last ADR about?'],['a12','f10']],
  ['gi9',[SA,SO,EA],'Fundamentals','Advanced','A stakeholder insists every quality attribute is "critical". How do you proceed?',
   'Handling quality-attribute conflict; facilitation skill.','Explain the conflicts → force ranking → price the extremes → record.',
   [['Qualities conflict inherently','conflict','tension','cannot maximise'],['Force ranking / sacrifice question','rank','top three','sacrifice','priorit'],['Price tags on extremes','cost','price','€','budget'],['Record in ADR/NFR doc','record','document','adr']],
   'Show the tensions (consistency vs availability, cost vs resilience), ask for the top three and the one they would sacrifice, and price the extremes — "99.999% costs 4× 99.9%". If everything is critical, nothing is; the design has no direction until they choose.',
   'Accepting the statement and promising everything.',
   ['What if they still refuse to rank?'],['f4','m7']],
  ['gi10',[SA,SO],'Fundamentals','Intermediate','What is technical debt and how do you manage it as an architect?',
   'Economic framing; management mechanics.','Metaphor precisely → quadrant → register → repayment budget.',
   [['Principal and interest framing','principal','interest','cost'],['Deliberate vs reckless distinction','deliberate','prudent','reckless','quadrant'],['Visible register with owners','register','owner','visible'],['Business-language pricing','incident','days per release','business']],
   'Debt has principal (rework) and interest (drag: slower features, more incidents). Deliberate, documented debt can be rational; toxic debt is invisible and unowned. A register with owners, interest priced in business terms, and a fixed repayment share of capacity.',
   'Debt = bad code; the fix = a big rewrite.',
   ['How do you prevent silent accrual?'],['f7']],

  /* ---- Trade-offs ---- */
  ['gi11',[SA,SO],'Trade-offs','Intermediate','Synchronous REST call or asynchronous event — how do you choose?',
   'The most common integration decision.','Decision questions → failure behaviour → consistency → examples.',
   [['Does the caller need the answer to proceed?','answer','proceed','immediate','query'],['Failure behaviour: chain vs buffer','outage','buffer','fails when','availability'],['Consistency and duplicate implications','eventual','duplicate','idempot'],['Concrete example each way','example','balance','notification']],
   'Sync when the caller needs the result to proceed (balance check before release); async when the fact must survive consumer outages and reach many consumers (customer updated). Sync couples availability and latency; async buys resilience at the price of eventual consistency and duplicate handling.',
   'A dogmatic answer either way ("always events").',
   ['What happens to your sync chain\'s availability across 4 services?'],['a6','d14']],
  ['gi12',[SA,SO,EA],'Trade-offs','Advanced','Consistency versus availability: give a business-grounded example of choosing each way.',
   'CAP applied, not recited.','CAP correctly → CP example → AP example → per-operation nuance.',
   [['Correct CAP framing (choice under partition)','partition','choose','cap'],['CP example with business reason','ledger','payment','reject','correct'],['AP example with business reason','catalogue','stale','available'],['Per-operation, not per-system','per operation','same system','mix']],
   'Under partition: a ledger refuses writes rather than risk double-spend (CP — correctness is the product); a product catalogue serves stale data rather than error pages (AP — availability is the revenue). Mature answer: choose per operation; one platform can serve both.',
   '"Pick two of three" folklore.',
   ['Where does PACELC extend this?'],['d1']],
  ['gi13',[SA,SO,CA],'Trade-offs','Advanced','Your design doubles infrastructure cost to gain one nine of availability. How do you decide?',
   'Cost-as-NFR reasoning; executive translation.','Quantify downtime cost → compare → business decision with evidence.',
   [['Downtime cost quantified','cost of downtime','per hour','revenue','impact'],['Compare spend vs exposure','compare','versus','exceed'],['Business owns the decision, architect prices it','business decision','present','options'],['Alternatives between the extremes','degrade','partial','cheaper']],
   'Price an hour of downtime (revenue, penalties, reputation), multiply by expected hours saved, compare with the added spend — and present intermediate options (multi-AZ + graceful degradation) before the multi-region hammer. The business decides; the architect makes the decision honest.',
   'Choosing either extreme on instinct.',
   ['Sketch the intermediate option for a payments API.'],['d5','m4']],
  ['gi14',[SA,AA],'Trade-offs','Intermediate','When is code duplication better than reuse?',
   'DRY nuance; coupling awareness.','DRY = knowledge, not text → boundary rule → shared-library trap.',
   [['DRY targets duplicated knowledge','knowledge','business rule','drift'],['Across boundaries duplication is often healthier','boundar','context','independent'],['Shared-library coupling trap','shared library','redeploy','lockstep']],
   'Deduplicate within a boundary; tolerate duplication across boundaries where the alternative is coupling — a shared "customer library" used by ten services means ten redeployments per change. Two contexts owning their own Address model beats one model both must negotiate.',
   'DRY as an absolute; extracting a library reflexively.',
   ['When is a shared library still right?'],['f6','d8']],
  ['gi15',[SA,SO],'Trade-offs','Expert','A perfect architecture delivered late versus a flawed one delivered on time — how do you actually navigate this?',
   'Judgement under delivery pressure.','Reject the framing → reversibility split → deliberate debt → guard the irreversibles.',
   [['Split by reversibility','reversible','irreversible','retrofit'],['Deliberate, documented shortcuts','deliberate','document','debt','adr'],['Protect the un-retrofittables','audit','idempot','data model','security'],['Roadmap for repayment','repay','next quarter','plan']],
   'The framing is false: split decisions by reversibility. Ship with deliberate, documented debt on reversible things; never compromise the un-retrofittables (idempotency, audit trails, data model, security basics). Record shortcuts as ADRs with repayment dates so the loan has terms.',
   'Piety ("never compromise quality") or surrender ("deadline wins").',
   ['Name three things you would never shortcut and why.'],['f7','f6']],

  /* ---- Microservices ---- */
  ['gi16',[SA,MA],'Microservices','Intermediate','What do microservices buy you and what do they cost?',
   'Balanced understanding; premium awareness.','Benefits (conditional!) → costs → the trade in one line.',
   [['Independent deploy/scale/failure isolation','independent','deploy','scale','isolation'],['Costs: network, consistency, ops surface','network','eventual','operational','latency','partial failure'],['Benefits conditional on boundaries','boundar','distributed monolith'],['Pays at organisational scale','team','organisational','coordination']],
   'They buy independent deployability, scaling, failure isolation and team parallelism — all conditional on correct boundaries. They cost partial failure, eventual consistency, sagas, contract governance and a serious platform. The trade: development coupling for operational complexity — worth it at multi-team scale, rarely before.',
   'Only benefits, or "they scale better" with no conditions.',
   ['When should a system stay a modular monolith?'],['d9']],
  ['gi17',[SA,MA],'Microservices','Advanced','How do you find service boundaries?',
   'DDD applied; boundary heuristics.','Bounded contexts via language → team/Conway check → transaction & chattiness tests.',
   [['Bounded contexts / language shifts','bounded context','language','means different'],['Team ownership alignment','team','conway','own'],['Transaction test','transaction','saga','span'],['Chattiness test','chatty','calls','hops']],
   'Start from bounded contexts — where the same word changes meaning, the model boundary lies. Check team ownership (Conway), then stress-test: would common operations span the boundary transactionally (redesign or wrong cut)? Count sync hops per scenario. Event storming surfaces all of this collaboratively.',
   'By nouns ("user service, order service") or by org chart alone.',
   ['A payment operation spans three of your candidate services. Now what?'],['d8','ms1']],
  ['gi18',[SA,MA],'Microservices','Advanced','Two services need to update their data consistently. Walk me through your options.',
   'Distributed-transaction maturity.','No 2PC → saga (orch vs choreo) → outbox/inbox → boundary challenge.',
   [['Rejects 2PC with reasons','2pc','two-phase','blocking','lock'],['Saga with compensation','saga','compensat'],['Outbox + idempotent consumers','outbox','inbox','idempot'],['Challenge the boundary itself','boundary','same service','redesign']],
   'First challenge the boundary — needing atomic cross-service updates constantly means the cut is wrong. Otherwise: saga with compensations (orchestrated if ≥4 steps or humans watch), events via transactional outbox, consumers idempotent via inbox, reconciliation as backstop. 2PC blocks, doesn\'t scale, and most infrastructure refuses it.',
   'Proposing distributed transactions or dual writes.',
   ['Which step of your saga is non-compensatable?'],['d2','ms1']],
  ['gi19',[SA,MA],'Microservices','Intermediate','How do you test a system of 20 microservices without an end-to-end bottleneck?',
   'Distributed testing strategy.','Pyramid per service → contracts at seams → thin smoke → resilience/canary.',
   [['Contract tests at every seam','contract','pact','consumer-driven'],['Realistic per-service integration (Testcontainers)','testcontainers','real database','integration'],['Thin e2e smoke only','thin','smoke','few'],['Production-aware: canary + SLOs','canary','production','slo']],
   'Per-service tests with real infrastructure via Testcontainers; consumer-driven contracts guarding every API and event seam — that layer replaces the release train; a thin journey smoke suite; and canary + SLO monitoring, because staging never has production\'s data shapes.',
   'A giant e2e environment as the primary safety net.',
   ['What do contract tests not catch?'],['j5','ms2']],
  ['gi20',[SA,MA],'Microservices','Expert','Your microservices deploy in lockstep and fail together. Diagnose and prescribe.',
   'Distributed-monolith recognition and repair.','Name it → root causes → repair path → prevention.',
   [['Distributed monolith diagnosis','distributed monolith','lockstep','coupled'],['Root causes: shared DB, sync chains, shared domain libs','shared database','synchronous','shared librar'],['Repair: contracts, data ownership, async seams','contract','ownership','async','outbox'],['Consider merging back','merge','consolidate','monolith']],
   'That is a distributed monolith — all the costs, none of the benefits. Causes: shared database, long sync chains, domain logic in shared libraries, boundaries cut against the domain. Repair by fixing data ownership and contracts seam by seam — or honestly merge services that always change together.',
   'Prescribing more services or a service mesh as the cure.',
   ['How do you decide merge vs repair per pair of services?'],['d9','ms2']],

  /* ---- Kafka ---- */
  ['gi21',[SA,KA,IA],'Kafka','Intermediate','Kafka versus a message queue — when each?',
   'Log vs queue model understanding.','Model difference → fan-out/replay → queue strengths → decision rule.',
   [['Log retained vs consumed queue','log','retain','delete','consume'],['Fan-out + replay as Kafka\'s edge','fan-out','multiple consumers','replay'],['Queue strengths: work distribution, per-message ack/DLQ','work','task','acknowledg'],['Decision by consumer count and replay need','decision','one consumer','many']],
   'Kafka is a retained log: many groups read independently, new consumers replay history — the integration-backbone property. Queues excel at work distribution with per-message semantics. One consumer doing jobs → queue is fine; many consumers or replay needs → Kafka.',
   'Kafka because it is standard, with no model distinction.',
   ['Where does a retry-topic pattern fit each model?'],['d13']],
  ['gi22',[KA,SA],'Kafka','Advanced','How do you choose an event key, and what goes wrong with a bad one?',
   'The central Kafka design decision.','Ordering scope → key properties → failure modes.',
   [['Key = ordering scope + partition placement','ordering','partition','scope'],['Stability and cardinality requirements','stable','cardinality','never change'],['Hot-key failure mode','hot','skew','one partition'],['Repartitioning consequences','repartition','remap','increase partitions']],
   'Key by the entity whose event order consumers need — customerId, accountId. Keys must be stable (never emails) with healthy cardinality. Bad keys create hot partitions (one whale customer) or broken ordering; and increasing partitions later remaps keys, so size generously up front.',
   'Random keys "for even distribution" where ordering mattered.',
   ['A single client generates 30% of events. Mitigations?'],['k1']],
  ['gi23',[KA,SA],'Kafka','Advanced','Explain exactly-once semantics in Kafka and its practical limits.',
   'Precision on the most misused Kafka claim.','What EOS covers → the boundary → the end-to-end answer.',
   [['EOS scope: Kafka-to-Kafka (transactions, Streams)','transactions','streams','within kafka'],['External systems break the guarantee','database','oracle','external','cannot be atomic'],['Exactly-once effect via outbox/inbox/idempotency','effect','outbox','inbox','idempot'],['read_committed and idempotent producer as ingredients','read_committed','idempotent producer','acks']],
   'Kafka transactions give exactly-once for consume-process-produce within Kafka (Streams). The moment you touch Oracle or a vendor API, offset commit and external effect cannot be atomic — you are back to at-least-once plus idempotency. End-to-end you build exactly-once *effect*: outbox, inbox, reconciliation.',
   '"We enabled EOS so duplicates are impossible."',
   ['Where do duplicates still come from with everything enabled?'],['k2','d3']],
  ['gi24',[KA,IA],'Kafka','Advanced','Design the failure handling for a critical Kafka consumer.',
   'Operational maturity: retries, DLT, replay.','In-memory retries → retry topics → DLT lifecycle → ordering caveat.',
   [['Tiered retries with backoff','retry','backoff','tier'],['DLT with alert + owner + runbook + replay','dead-letter','dlt','alert','replay'],['Ordering sacrifice of retry topics','ordering','overtake','sacrifice'],['Idempotent reprocessing precondition','idempot','duplicate']],
   'Transient errors: in-memory retries with backoff; medium outages: retry topics (5m/1h tiers) so the partition is not blocked; poison messages: DLT carrying error context — with alerting, an owner, a runbook and a replay tool. Say aloud that retry topics sacrifice per-key ordering; where order is sacred, block-and-alert instead.',
   'Infinite in-place retries, or a DLT nobody monitors.',
   ['When is block-and-alert better than retry topics?'],['k4']],
  ['gi25',[KA,SA],'Kafka','Intermediate','A consumer group\'s lag is growing steadily. Walk me through your diagnosis.',
   'Operational debugging method.','Confirm scope → consumer health → throughput maths → fixes.',
   [['Scope: which partitions, since when','partition','which','when','deploy'],['Consumer health: rebalances, errors, poll timing','rebalance','max.poll','error','slow'],['Throughput vs partition maths','throughput','partitions','parallel'],['Fixes: scale to partition count, batch, async, more partitions (with key caveat)','scale','batch','add consumers']],
   'Check whether lag is uniform or per-partition (hot key?), correlate with deploys/rebalances, measure per-message processing time against arrival rate. Fixes in order: consumer efficiency (batching, async IO), scale members up to partition count, then more partitions — acknowledging the key-remap cost.',
   'Immediately adding partitions without diagnosis.',
   ['Lag is on one partition only — what is your first suspicion?'],['k4','k1']],

  /* ---- Java / Spring ---- */
  ['gi26',[JA,AA,SA],'Java & Spring','Intermediate','Where do transaction boundaries belong in a Spring service, and what are the classic traps?',
   'Production Spring knowledge.','Application-service methods → traps (self-invocation, rollback rules, remote calls inside tx).',
   [['Use-case/application-service level','application service','use case','method'],['Self-invocation bypasses proxy','self-invocation','proxy','same class'],['Rollback defaults (unchecked only)','rollback','checked','unchecked'],['No remote calls inside transactions','remote','http','kafka','inside']],
   'One use case, one transaction, at the application-service layer. Traps: self-invocation skips the proxy silently; checked exceptions commit by default; REQUIRES_NEW takes a second connection; and never make remote calls inside a transaction — commit state plus outbox row, publish after.',
   'Sprinkling @Transactional until errors stop.',
   ['Why is a slow HTTP call inside a transaction a pool killer?'],['j2']],
  ['gi27',[JA,AA],'Java & Spring','Intermediate','Optimistic versus pessimistic locking — how do you choose?',
   'Concurrency control judgement.','Mechanics → contention profile → retry design → hot-row exception.',
   [['Mechanics of both','version','for update','lock'],['Choose by contention','contention','conflict rate','hot'],['Retry whole use case on optimistic conflict','retry','use case','optimisticlock'],['Pessimistic for hot rows with timeouts','balance','timeout','deadlock','ordering']],
   'Optimistic (@Version) for low contention: no locks held, conflicts retried at use-case level — also the right default under event redelivery. Pessimistic (FOR UPDATE) for genuinely hot rows like account balances under concurrent posting, with lock timeouts and consistent ordering to avoid deadlocks.',
   'One mechanism everywhere, or retrying just the SQL statement.',
   ['What does the retry of an optimistic conflict have to include?'],['j2']],
  ['gi28',[JA,SA],'Java & Spring','Advanced','Your Spring Boot pod gets OOMKilled under load. Diagnose.',
   'JVM-in-container competence.','Container memory anatomy → sizing → heap dump → leak vs sizing.',
   [['Heap is not the only memory (metaspace, threads, buffers)','metaspace','direct','thread','off-heap'],['MaxRAMPercentage / limit alignment','maxram','limit','75'],['Heap dump / analysis path','heap dump','mat','analyz'],['Distinguish sizing error from leak','leak','sizing','grow']],
   'OOMKilled means the container breached its limit — usually sizing: heap + metaspace + threads + direct buffers exceed the pod limit. Align MaxRAMPercentage with headroom, verify under load, and only then hunt leaks with heap dumps. Three thread dumps also reveal pool exhaustion masquerading as memory pressure.',
   '"Increase the memory" with no anatomy.',
   ['What belongs in JVM memory besides heap?'],['j4','j2']],
  ['gi29',[JA,AA],'Java & Spring','Advanced','Show me how you would make a payment-initiation endpoint idempotent in Spring Boot.',
   'Applied idempotency implementation.','Client key → storage in same tx → replay semantics → edge cases.',
   [['Client-supplied Idempotency-Key','idempotency-key','client','header'],['Key + result stored in the same transaction','same transaction','store','result'],['Replay returns original result','replay','same response','stored'],['Concurrent duplicate handling + TTL','concurrent','unique constraint','ttl','window']],
   'The client supplies an Idempotency-Key; the service inserts it (unique constraint) with the request hash in the same transaction as the payment creation and stores the response; retries return the stored response; concurrent duplicates lose on the constraint and read the winner\'s result. TTL matches the retry horizon; mismatched payload under the same key is a 422.',
   'Deduplicating in an in-memory map.',
   ['What if the same key arrives with a different amount?'],['j3','d3']],
  ['gi30',[JA,SA],'Java & Spring','Intermediate','Compose Resilience4j decorators for a flaky vendor call — in what order, and why?',
   'Resilience mechanics precision.','Order outermost→innermost → reasoning per adjacency.',
   [['Correct order: bulkhead→ratelimit→breaker→retry→timeout','bulkhead','rate','breaker','retry','timeout','order'],['Retry inside breaker (failures trip it)','retry inside','trip'],['Timeout bounds each attempt','each attempt','bound'],['Fallback and metrics','fallback','metric','alert']],
   'Bulkhead(RateLimiter(CircuitBreaker(Retry(TimeLimiter(call))))). Retries sit inside the breaker so repeated failures trip it; the timeout bounds each individual attempt; the bulkhead caps total concurrency so a vendor hang cannot drain the service. Every decorator exports metrics; open breakers page someone.',
   'Random order; retry wrapping the breaker.',
   ['What changes for an idempotent GET vs a POST?'],['j4','d4']],

  /* ---- Security ---- */
  ['gi31',[SEC,SA,SO],'Security','Intermediate','Design authentication and authorisation for a system with humans and services.',
   'Modern IAM stack fluency.','OIDC for humans → OAuth CC/mTLS for services → RBAC/ABAC → non-negotiables.',
   [['OIDC via central IdP for humans','oidc','idp','sso'],['Client credentials / mTLS for services','client credentials','mtls','workload'],['JWT validation incl. audience','audience','signature','expiry'],['RBAC coarse + ABAC fine','rbac','abac','role','attribute']],
   'Humans authenticate via OIDC against the corporate IdP; services use client-credentials tokens and/or mesh-issued mTLS identity. Resource servers validate JWTs fully — signature, expiry, issuer, audience. RBAC for coarse entitlements, ABAC policies for contextual rules; never build your own authentication.',
   'Custom login tables; "internal so no auth needed".',
   ['Why is audience validation the commonly missed one?'],['d15']],
  ['gi32',[SEC,SA],'Security','Advanced','Walk me through threat modelling a new payment API.',
   'Structured security thinking at design time.','DFD + trust boundaries → STRIDE walk → mitigations → verification tie-in.',
   [['Data-flow diagram with trust boundaries','data flow','trust boundar','dfd'],['STRIDE per element','stride','spoofing','tampering','repudiation'],['Mitigate/eliminate/transfer/accept','mitigat','accept','eliminate'],['Verification linkage (tests, pentest scope)','verify','test','pentest']],
   'Draw the DFD — client, gateway, service, DB, vendor — and mark every trust crossing. Walk STRIDE per element: spoofed clients (mTLS/tokens), tampered messages (TLS, signing), repudiation (non-repudiable audit), disclosure (masking, least privilege), DoS (rate limits), elevation (authz per request). Each threat gets mitigate/eliminate/transfer/accept with an owner, and the pentest scope follows the model.',
   'Jumping straight to "we use TLS and a WAF".',
   ['Which STRIDE category does maker-checker address?'],['d16']],
  ['gi33',[SEC,SA,CA],'Security','Advanced','What does Zero Trust concretely change in a Kubernetes-based platform?',
   'Beyond-the-slogan implementation knowledge.','Identity per workload → segmentation → secrets → continuous verification.',
   [['mTLS workload identity (mesh)','mtls','mesh','identity'],['Default-deny NetworkPolicies','default-deny','networkpolic','segment'],['Short-lived vault-issued secrets','vault','short-lived','rotate'],['AuthZ per request, not per zone','per request','no trusted zone','verify']],
   'Concretely: every workload gets cryptographic identity via mesh mTLS; NetworkPolicies default-deny so lateral movement dies; secrets are short-lived and vault-issued, never static in configs; every request is authenticated and authorised regardless of origin. The "trusted internal network" stops existing as a concept.',
   'Quoting the slogan; buying a "Zero Trust product".',
   ['What is the incremental adoption order you would choose?'],['d15','d12']],
  ['gi34',[SEC,SA],'Security','Intermediate','How do you keep secrets out of code, config and logs?',
   'Secrets hygiene end to end.','Vault issuance → injection → rotation → log protection.',
   [['Central vault, short-lived credentials','vault','short-lived','issue'],['Runtime injection, not files in git','inject','environment','never in git'],['Rotation designed in','rotat'],['Log allowlisting / masking','log','mask','allowlist','leak']],
   'Secrets live in a vault and are injected at runtime, short-lived where possible so rotation is continuous rather than heroic. Nothing in git, ever — scanners enforce it. Logs use structured fields with an allowlist of loggable data; tokens and credentials are masked at the logging framework level, not by developer discipline.',
   '"They are in application.yml but the repo is private."',
   ['Why do short-lived credentials beat rotated long-lived ones?'],['d15','j3']],

  /* ---- Cloud / Data / Platform ---- */
  ['gi35',[CA,SA,SO],'Cloud','Intermediate','What is a landing zone and why does it come before the first workload?',
   'Cloud foundation literacy.','Components → why first → guardrails as code.',
   [['Account/network/identity structure','account','network','identity','structure'],['Guardrails as policy-code','guardrail','policy','deny'],['Central logging and shared services','logging','shared','dns','secrets'],['Retrofit cost argument','retrofit','before','rebuild']],
   'The governed foundation: account structure for blast-radius and cost boundaries, hub-spoke networking with egress control, identity federation, policy-as-code guardrails (deny public buckets, require encryption), central logging, shared services. Workloads built before it get rebuilt after it — twice the cost.',
   'Starting with a single account and "we will organise later".',
   ['Which guardrails would you insist on for a bank?'],['c1']],
  ['gi36',[CA,SO,EA],'Cloud','Advanced','How do you think about cloud vendor lock-in?',
   'Nuanced economics over phobia.','Lock-in as priced trade → portability tax → per-dependency decision → exit plans.',
   [['Lock-in is a priced trade-off, both directions','price','trade','both'],['Portability has an ongoing cost','portability','tax','lowest common'],['Decide per dependency by switching cost','per service','switching cost','commodity'],['Rehearsed exit plans over live multi-cloud','exit plan','rehears','regulator']],
   'Avoiding lock-in also costs — running your own Kafka to stay "portable" is a standing tax against a hypothetical migration. Decide per dependency: deep integration where the service is commodity-shaped (managed Postgres speaks SQL), caution where exit is realistic. Regulators asking for exit capability are satisfied by documented, rehearsed migration paths, not symmetric multi-cloud.',
   'Absolute avoidance or total indifference.',
   ['When is genuine multi-cloud justified?'],['c2','a5']],
  ['gi37',[DA,SA,SO],'Data','Intermediate','How do you choose a database for a new service?',
   'Store-selection method over brand loyalty.','Requirements first → shape/consistency/scale/query questions → default + escape hatches.',
   [['Requirements before products','requirement','before','shape'],['Data shape and access patterns','relational','document','graph','access pattern'],['Consistency and scale needs','consistency','acid','scale'],['Relational default until pressure; polyglot with one SoR','default','polyglot','system of record']],
   'Write the requirements first: data shape, access patterns, consistency, volume, ops constraints. Relational is the defensible default for transactional systems of record; move families only under specific pressure (traversal → graph, relevance → search, extreme writes → wide-column) — and every derived store must be rebuildable from the SoR.',
   'Choosing by what is fashionable or familiar alone.',
   ['Your read model diverges from the SoR — what is the discipline?'],['dt1','a8']],
  ['gi38',[DA,EA],'Data','Advanced','What does good data ownership look like in a large organisation?',
   'Governance realism.','One SoR per entity → owner/steward roles → contracts → quality at source.',
   [['One system of record per entity','system of record','one master','golden'],['Named owners and stewards','owner','steward','accountab'],['Data contracts with quality SLOs','contract','freshness','quality'],['Quality fixed at source, not downstream','source','cleansing','downstream']],
   'Every important entity has exactly one system of record and a named owner accountable for meaning, quality and access. Shared datasets carry contracts — schema, semantics, freshness SLOs, change process. Quality is measured and fixed at the source; downstream cleansing is debt that regenerates forever.',
   '"The data team owns all data."',
   ['How does data mesh change (or not change) this?'],['dt2']],
  ['gi39',[PA,EA,SA],'Cloud','Advanced','What makes an internal platform succeed or die?',
   'Platform-as-product thinking.','Product mindset → golden paths → adoption metrics → cognitive-load framing.',
   [['Platform as product with users','product','user','self-service'],['Golden paths making compliance easy','golden path','template','easy'],['Measured by adoption, not mandate','adoption','voluntary','mandate'],['Reduces team cognitive load','cognitive load','abstract','undifferentiated']],
   'Platforms succeed as products: self-service golden paths that make the right way the fast way, measured by voluntary adoption. They die as mandates: ticket queues to a bottleneck team, abstractions leakier than what they hide. The test — does the platform reduce stream-aligned teams\' cognitive load or add to it?',
   'A platform defined by an org chart and a mandate memo.',
   ['What belongs in a new-service golden path for a bank?'],['m5','c1']],

  /* ---- System design ---- */
  ['gi40',[SA,SO],'System design','Intermediate','Design a URL-shortening service. Start wherever you like.',
   'Method under a deceptively simple prompt.','Clarify → estimate → API/data → encoding → redirect path scale → failures.',
   [['Clarifies scale and requirements first','how many','scale','clarify','requirement'],['Read-heavy estimate shapes design','read-heavy','ratio','cache'],['Key-generation collision strategy','collision','base62','counter','hash'],['Redirect path: cache + availability focus','redirect','cache','latency','availability']],
   'Clarify: volume (writes/day, redirect ratio ~100:1), latency, custom aliases, expiry, analytics. Estimate before designing. Key generation: counter+base62 or pre-generated key pool (no collisions) vs hashing (collision checks). The redirect path is the product: cache-heavy, horizontally scaled, availability over write consistency. Then failures: cache stampede, hot links, and the analytics pipeline as async events.',
   'Jumping to a schema without volumes or clarification.',
   ['How do you handle a link going viral (hot key)?'],['d6','cs1']],
  ['gi41',[SA,SO],'System design','Advanced','Design a notification platform (email, SMS, push) for many producer teams.',
   'Async design, ownership, failure realism.','Ingestion contract → queueing/prioritisation → provider adapters → dedupe/preferences → observability.',
   [['Event/API ingestion with a contract','contract','api','event','producer'],['Priority queues and rate control per channel','priority','queue','rate'],['Provider adapters with failover','provider','adapter','failover','vendor'],['Idempotency, preferences, quiet hours, audit','idempot','preference','dedup','audit']],
   'Producers publish notification requests (event or API) against a versioned contract with idempotency keys. The platform prioritises (OTP beats marketing), rate-controls per provider, and routes through provider adapters with health-based failover. Preferences/consent and quiet hours are first-class; every notification\'s lifecycle is auditable; failed sends retry with backoff into a DLT with replay.',
   'A cron job reading a notifications table per channel.',
   ['An OTP is 30 seconds late — walk through your diagnosis.'],['cs4','d14']],
  ['gi42',[SA,SO,MA],'System design','Expert','Design an e-commerce checkout that survives Black Friday.',
   'Scale + consistency + failure design under pressure.','Load shape → critical path minimisation → inventory strategy → payment idempotency → degradation menu.',
   [['Peak-factor sizing and load testing','peak','black friday','factor','load test'],['Minimal synchronous critical path','critical path','async','defer'],['Inventory: reservation with expiry','reserv','oversell','expiry'],['Payment idempotency + saga compensation','idempot','saga','compensat'],['Designed degradation (queue, disable features)','degrad','queue','shed']],
   'Size to peak with headroom and prove it by load test. Keep the paid path minimal-synchronous: reserve inventory (with expiring holds), authorise payment idempotently; everything else — emails, analytics, recommendations — async. Failures compensate via saga (release holds). Degradation menu agreed in advance: queue entry, disable recommendations, never break payment integrity.',
   'Scaling everything ×10 with no path analysis.',
   ['Payment succeeded but order confirmation failed — recover.'],['cs3','d2']],

  /* ---- Failure & recovery ---- */
  ['gi43',[SA,SO],'Failure & recovery','Advanced','A dependency\'s latency went from 50 ms to 5 s. Trace the blast radius through an unprotected system and then through a protected one.',
   'Cascading-failure mechanics fluency.','Unprotected chain → resource exhaustion → protected version pattern by pattern.',
   [['Thread/connection pool exhaustion story','pool','exhaust','block','thread'],['Upstream propagation + retry amplification','cascade','upstream','retry storm'],['Timeouts + breakers cut the chain','timeout','breaker','fail fast'],['Bulkheads + load shedding contain','bulkhead','shed','isolat']],
   'Unprotected: callers block 5 s each, pools exhaust, the caller\'s callers block, retries amplify load, the estate browns out — a latency problem becomes an availability cascade. Protected: tight timeouts fail attempts fast, the breaker opens and serves fallbacks, the bulkhead caps threads exposed, load shedding protects the hot path. Same trigger, contained blast.',
   'Only naming patterns without the failure narrative.',
   ['Which single control gives the most protection per unit effort?'],['d4']],
  ['gi44',[SA,SO,CA],'Failure & recovery','Advanced','Define and defend RTO/RPO for a tier-1 service, then design to them.',
   'Business-driven resilience design.','Elicit numbers from downtime/data-loss cost → tier architecture → test regime.',
   [['RTO/RPO from business cost, not instinct','cost','business','tolerate'],['Architecture tier follows the numbers','active-active','standby','failover','tier'],['Async replication ⇒ honest nonzero RPO','async','lag','honest'],['Rehearsed failover / game days','game day','rehears','test','evidence']],
   'Ask what an hour of downtime and a minute of lost data cost — the answers price the tier: backups (days/hours) → warm standby → automated failover → active-active. State the honest RPO of async replication and who reconciles the tail. Then rehearse: an untested failover is a document. Report achieved-vs-promised after every game day.',
   'RTO zero everywhere; DR validated on paper.',
   ['Your replication lag was 8 s at failover. Now what?'],['d5','b9']],
  ['gi45',[SA,SO],'Failure & recovery','Expert','Production incident: orders are being processed twice. Lead the response and the fix.',
   'Incident leadership + idempotency forensics.','Stabilise → diagnose duplicate source → systemic fix → prevention.',
   [['Immediate containment with business priority','contain','stop','impact','first'],['Duplicate-source taxonomy: retries, redelivery, replay, rebalance','retry','redelivery','replay','rebalance'],['Idempotency as the systemic fix','idempot','inbox','key','constraint'],['Reconciliation + postmortem prevention','reconcil','postmortem','fitness']],
   'Contain first: pause the consumer or enable the dedupe guard, quantify impact, communicate. Diagnose which duplicate source: client retries without keys, consumer redelivery around rebalances, a replay into a non-idempotent path. Fix systemically — unique business keys and inbox dedupe in the same transaction — then reconcile the damage with audit, and add a duplicate-detection fitness check so the class of bug stays dead.',
   'Deleting duplicate rows and closing the ticket.',
   ['Why is "we fixed the data" not the end of this incident?'],['d3','b9']],

  /* ---- Leadership / Communication ---- */
  ['gi46',[SA,SO,EA],'Leadership','Advanced','How do you influence a decision when you have no authority over the teams involved?',
   'The core architect leadership skill.','Credibility → shared context → framing per audience → escalation as last resort.',
   [['Credibility built over time','credibilit','track record','trust'],['Co-creation over decree','involve','workshop','together','socialise'],['Framing in each stakeholder\'s currency','currency','risk','cost','frame'],['1:1 pre-socialisation before meetings','1:1','before the meeting','pre']],
   'Influence runs on credibility, shared context and framing. Involve people in the reasoning — co-created decisions get championed, decreed ones get complied with. Translate to each audience\'s currency, pre-socialise 1:1 so nobody is surprised publicly, and spend "I strongly object" capital rarely enough that it retains value.',
   '"I escalate to their manager."',
   ['A team quietly ignores the agreed decision — next move?'],['m6']],
  ['gi47',[SA,SO,EA],'Leadership','Advanced','Explain a technically risky situation to a non-technical executive in under a minute. Pick one and go.',
   'Executive translation under constraint.','BLUF → business consequence → options with price → clear ask.',
   [['Leads with the ask/decision','decision','ask','recommend','first'],['Business consequence, zero jargon','customer','revenue','headline','fine'],['Options with cost and risk','option','cost','risk'],['Concrete example delivered, not described','example','payment','duplicate']],
   '"I need a decision by Friday. A network glitch can currently charge customers twice — that is a press-headline risk. Fixing it properly costs six weeks of one team; a partial guard costs one week and halves the risk. I recommend the full fix; waiting costs us roughly one incident per quarter. Which do you want?"',
   'Explaining idempotency mechanics to a CFO.',
   ['The executive picks the cheap option — your response?'],['m7']],
  ['gi48',[SA,EA],'Leadership','Expert','Two teams both claim ownership of a capability; the architecture suffers. Resolve it.',
   'Socio-technical judgement; Conway fluency.','Diagnose via Conway → decide ownership by cognitive load and change cadence → make the boundary contractual.',
   [['Conway framing: ownership conflict = architecture conflict','conway','mirror','ownership'],['Decide by domain fit, cadence, cognitive load','cognitive load','cadence','domain'],['One owner, contractual consumers','one owner','contract','consumer'],['Record and revisit','adr','review','revisit']],
   'Dual ownership is a boundary bug: the architecture will mirror the standoff. Facilitate a decision on domain fit, change cadence and team cognitive load; give the capability exactly one owner and make the other team a contractual consumer with a real interface. Record it as an ADR with a review date — and accept that the org design decision *is* the architecture decision.',
   'Splitting the difference with shared ownership.',
   ['What if management refuses to choose?'],['m5','m6']],
  ['gi49',[SA,SO],'Leadership','Intermediate','How do you mentor developers toward architectural thinking?',
   'Scaling judgement, not gatekeeping.','Delegate decisions with frameworks → pair on firsts → review by exception → measure independence.',
   [['Frameworks/ADR templates over answers','framework','template','adr','themselves'],['Pairing on first instances','pair','first','together'],['Review by exception, not bottleneck','exception','bottleneck','delegate'],['Success = good decisions in your absence','absence','independen','without me']],
   'Give frameworks, not answers: decision checklists, ADR templates, trade-off vocabulary. Pair on the first instance of each decision type, then delegate the rest and review by exception. Ask "what would change your mind?" more than "here is the answer". Success metric: the quality of decisions made when you are not in the room.',
   'Reviewing every design personally forever.',
   ['A mentee\'s ADR reaches a conclusion you disagree with but is defensible. Approve?'],['m6']],
  ['gi50',[SA,SO,EA],'Behavioural','Intermediate','Tell me about a time you were pressured to approve a solution you considered risky.',
   'Integrity under pressure; STAR discipline.','STAR: situation → your analysis → action (written risk, alternatives, escalation path) → result + reflection.',
   [['STAR structure evident','situation','action','result'],['Risk made explicit in writing','writing','risk register','document'],['Constructive alternative offered','alternative','smaller','instead'],['Clear personal boundary','could not approve','declined','conditions']],
   'STAR: a deadline-driven push to skip screening-queue durability; I wrote the risk with a concrete failure scenario and an owner, offered a one-week durable-queue alternative, and stated what I could and could not approve. The alternative shipped; the risk register entry later justified the follow-up work. Reflection: written risk with an owner changes conversations.',
   'Either caving silently or heroic refusal with no alternative.',
   ['What would you have done had they overridden you?'],['m9','m6']],

  /* ---- Enterprise / governance ---- */
  ['gi51',[EA,SO],'Fundamentals','Advanced','How should an architecture review board work so teams stop routing around it?',
   'Governance design maturity.','Decision-scoped, fast, advisory-first → guardrails absorb the routine → exceptions as telemetry.',
   [['Scope: only genuinely significant decisions','scope','significant','novel'],['Speed and advisory posture','fast','days','advisory','collaborative'],['Guardrails/policy-as-code for the routine','guardrail','pipeline','policy'],['Exception process feeding standards review','exception','telemetry','feedback']],
   'Boards fail by reviewing everything slowly. Fix: decision-scoped ("we review X, Y, Z; the rest is yours"), turnaround in days, advisory-first with pre-reads, staffed by people close to delivery. Routine compliance moves into pipelines as guardrails. A healthy exception process is telemetry — many exceptions against one standard means the standard is wrong.',
   'More mandatory gates and templates.',
   ['What three decision types would you scope a bank\'s ARB to?'],['m3']],
  ['gi52',[EA],'Fundamentals','Expert','How do you measure whether the architecture function is actually helping?',
   'Outcome orientation over activity.','Flow/stability metrics → QA compliance → decision health → anti-vanity stance.',
   [['DORA flow and stability metrics','lead time','deploy','mttr','change failure'],['SLO/fitness-function attainment','slo','fitness','attain'],['Decision health: ADR coverage, exception counts','adr coverage','exception','decision'],['Rejects vanity metrics','diagram','vanity','activity']],
   'Architecture succeeds when the organisation changes software safely, quickly and affordably: lead time, deploy frequency, change-failure rate, MTTR; SLO and fitness-function attainment; unit-cost trends; and decision health — ADR coverage, exception rates, cross-team coordination needed per change. Diagrams produced and boards held measure activity, not value.',
   'Counting reviews performed and standards published.',
   ['Which single metric would you start with and why?'],['m8']],
  ['gi53',[EA,SO],'Trade-offs','Expert','The business wants a capability in 6 months; proper platform runway needs 9. Options?',
   'Strategy sequencing under pressure.','Options with real costs → thin-runway slicing → deliberate-debt route → honest recommendation.',
   [['Multiple genuine options priced','option','cost','trade'],['Thin slice of runway serving this capability first','thin','slice','minimum','subset'],['Tactical build with planned migration as explicit debt','tactical','debt','migrate later','throwaway'],['Honest risk statement to sponsors','risk','honest','executive']],
   'Three honest options: (1) descope the capability to fit a thin runway slice — build only the platform pieces this capability needs; (2) tactical build now with a recorded migration debt and a funded repayment plan — the loan has terms or it is a lie; (3) move the date, priced. Present all three with risk; refuse the fourth option everyone secretly plans — tactical forever.',
   'Promising both dates by "working smart".',
   ['Who should make the final call, and on what evidence?'],['m1','f7']],
  ['gi54',[SA,SO,IA],'Trade-offs','Advanced','A vendor product covers 70% of the need. Customise it, build around it, or build it all?',
   'Sourcing nuance beyond build-vs-buy.','Interrogate the 30% → customisation-debt warning → wrap/extend option → Wardley framing.',
   [['Is the 30% differentiating or commodity?','differentiat','commodity','30'],['Customisation debt / upgrade tax','customis','upgrade','debt'],['Wrap with ACL, build the delta beside it','wrap','acl','around','extend'],['Exit and lock-in check','exit','lock-in']],
   'Ask what the missing 30% is: commodity → configure and wait for the roadmap (in the contract); differentiating → build the delta *beside* the product behind an anti-corruption layer, never deep customisation — heavily customised products become unupgradeable, the worst of build and buy. Check exit costs before deepening the marriage.',
   'Whichever the vendor\'s sales engineer suggested.',
   ['Where does the ACL sit and what does it protect?'],['a5','a4']],
  ['gi55',[SA,AA],'Summary','Intermediate','Summarise the architecture you designed today in five sentences for the hiring panel.',
   'Synthesis and communication compression.','Problem → shape → 2 key decisions with trade-offs → risk + next step.',
   [['Problem and drivers in one line','problem','goal','driver'],['Overall shape named','architecture','event-driven','services','monolith'],['Two decisions with the trade-off stated','decision','trade-off','chose'],['Top risk and next validation step','risk','next','validate','poc']],
   'One sentence of problem and dominant drivers; one naming the shape; two for the decisive trade-offs (e.g. orchestrated saga for auditability over choreography\'s looseness; outbox-based consistency accepting eventual reads); one naming the biggest risk and the spike that retires it. Stop talking after sentence five.',
   'A rambling re-walk of the whole session.',
   ['Now the one-sentence version.'],['m7','mo5']]
  ];

  D.interviewQs = (D.interviewQs || []).concat(Q.map(function (q) {
    return { id: q[0], role: q[1], cat: q[2], difficulty: q[3], q: q[4], testing: q[5], structure: q[6],
      kp: q[7], strong: q[8], weak: q[9], followups: q[10], lessons: q[11] };
  }));
})(window.SAA.data);
